            if (ret <= 0 && ERR_count_to_mark() == 0)
                ERR_raise_data(ERR_LIB_EVP, EVP_R_PROVIDER_SIGNATURE_FAILURE,
                    "%s digest_sign:%s", signature->type_name, desc);
            ERR_clear_last_mark();
            return ret;
        }
    }

if (EVP_CIPHER_get_mode(ciph) == EVP_CIPH_CCM_MODE) {
    if (!EVP_CipherInit_ex(ciph_ctx, ciph, NULL, NULL, NULL, enc)
        || EVP_CIPHER_CTX_ctrl(ciph_ctx, EVP_CTRL_AEAD_SET_IVLEN, 12,
               NULL)
            <= 0
        || EVP_CIPHER_CTX_ctrl(ciph_ctx, EVP_CTRL_AEAD_SET_TAG,
               (int)taglen, NULL)
            <= 0
        || EVP_CIPHER_CTX_ctrl(ciph_ctx, EVP_CTRL_CCM_SET_IV_FIXED,
               (int)ivlen, iv)
            <= 0
        || !EVP_CipherInit_ex(ciph_ctx, NULL, NULL, key, NULL, enc)) {
        ERR_raise(ERR_LIB_SSL, ERR_R_INTERNAL_ERROR);
        return OSSL_RECORD_RETURN_FATAL;
    }
} else {
    if (!EVP_CipherInit_ex(ciph_ctx, ciph, NULL, key, iv, enc)) {
        ERR_raise(ERR_LIB_SSL, ERR_R_INTERNAL_ERROR);
        return OSSL_RECORD_RETURN_FATAL;
    }
}

switch (cmd) {
case X509_L_FILE_LOAD:
    if (argl == X509_FILETYPE_DEFAULT) {
        file = ossl_safe_getenv(X509_get_default_cert_file_env());
        if (file)
            ok = (X509_load_cert_crl_file_ex(ctx, file, X509_FILETYPE_PEM,
                      libctx, propq)
                != 0);
        else
            ok = (X509_load_cert_crl_file_ex(
                      ctx, X509_get_default_cert_file(),
                      X509_FILETYPE_PEM, libctx, propq)
                != 0);

        if (!ok)
            ERR_raise(ERR_LIB_X509, X509_R_LOADING_DEFAULTS);
    } else {
        if (argl == X509_FILETYPE_PEM)
            ok = (X509_load_cert_crl_file_ex(ctx, argp, X509_FILETYPE_PEM,
                      libctx, propq)
                != 0);
        else
            ok = (X509_load_cert_file_ex(ctx, argp, (int)argl, libctx,
                      propq)
                != 0);
    }
    break;
}

if (OPCODE_HAS_JUMP(instr->i_opcode)) {
    instruction *target = &instrs->s_instrs[instr->i_target];
    instr->i_oparg = target->i_offset;
    if (instr->i_opcode == END_ASYNC_FOR) {
        // sys.monitoring needs to be able to find the matching END_SEND
        // but the target is the SEND, so we adjust it here.
        instr->i_oparg = offset - instr->i_oparg - END_SEND_OFFSET;
    }
    else if (instr->i_oparg < offset) {
        assert(IS_BACKWARDS_JUMP_OPCODE(instr->i_opcode));
        instr->i_oparg = offset - instr->i_oparg;
    }
    else {
        assert(!IS_BACKWARDS_JUMP_OPCODE(instr->i_opcode));
        instr->i_oparg = instr->i_oparg - offset;
    }
    if (instr_size(instr) != isize) {
        extended_arg_recompile = 1;
    }
}

if(type2len >= 48) {
  target_info_len = Curl_read16_le(&type2[40]);
  target_info_offset = Curl_read32_le(&type2[44]);
  if(target_info_len > 0) {
    if((target_info_offset > type2len) ||
       (target_info_offset + target_info_len) > type2len ||
       target_info_offset < 48) {
      infof(data, "NTLM handshake failure (bad type-2 message). "
            "Target Info Offset Len is set incorrect by the peer");
      return CURLE_BAD_CONTENT_ENCODING;
    }

    curlx_free(ntlm->target_info); /* replace any previous data */
    ntlm->target_info = curlx_memdup(&type2[target_info_offset],
                                     target_info_len);
    if(!ntlm->target_info)
      return CURLE_OUT_OF_MEMORY;
  }
}
